    47→func ProvideService(cfg *setting.Cfg, sqlStore db.DB, ac ac.AccessControl,
    48→	routeRegister routing.RouteRegister, features featuremgmt.FeatureToggles,
    49→	secrets secrets.Service, usageStats usagestats.Service, registerer prometheus.Registerer,
    50→	settingsProvider setting.Provider, licensing licensing.Licensing) *Service {
    51→	fbStrategies := []ssosettings.FallbackStrategy{
    52→		strategies.NewOAuthStrategy(cfg),
    53→		strategies.NewLDAPStrategy(cfg),
    54→	}
    55→
    56→	configurableProviders := make(map[string]bool)
    57→	for provider, enabled := range cfg.SSOSettingsConfigurableProviders {
    58→		configurableProviders[provider] = enabled
    59→	}
    60→
    61→	providersList := ssosettings.AllOAuthProviders
    62→
    63→	if features.IsEnabledGlobally(featuremgmt.FlagSsoSettingsLDAP) {
    64→		providersList = append(providersList, social.LDAPProviderName)
    65→		configurableProviders[social.LDAPProviderName] = true
    66→	}
    67→
    68→	if licensing.FeatureEnabled(social.SAMLProviderName) {
    69→		fbStrategies = append(fbStrategies, strategies.NewSAMLStrategy(settingsProvider))
    70→
    71→		if features.IsEnabledGlobally(featuremgmt.FlagSsoSettingsSAML) {
    72→			providersList = append(providersList, social.SAMLProviderName)
    73→			configurableProviders[social.SAMLProviderName] = true
    74→		}
    75→	}
    76→
    77→	store := database.ProvideStore(sqlStore)
    78→
    79→	svc := &Service{
    80→		logger:                log.New("ssosettings.service"),
    81→		cfg:                   cfg,
    82→		store:                 store,
    83→		ac:                    ac,
    84→		fbStrategies:          fbStrategies,
    85→		secrets:               secrets,
    86→		metrics:               newMetrics(registerer),
    87→		providersList:         providersList,
    88→		configurableProviders: configurableProviders,
    89→		reloadables:           make(map[string]ssosettings.Reloadable),
    90→	}
    91→
    92→	usageStats.RegisterMetricsFunc(svc.getUsageStats)
    93→
    94→	if features.IsEnabledGlobally(featuremgmt.FlagSsoSettingsApi) {
    95→		ssoSettingsApi := api.ProvideApi(svc, routeRegister, ac)
    96→		ssoSettingsApi.RegisterAPIEndpoints()
    97→	}
    98→
    99→	return svc
   100→}
