   104→func (s *Service) GetForProvider(ctx context.Context, provider string) (*models.SSOSettings, error) {
   105→	dbSettings, err := s.store.Get(ctx, provider)
   106→	if err != nil && !errors.Is(err, ssosettings.ErrNotFound) {
   107→		return nil, err
   108→	}
   109→
   110→	if dbSettings != nil {
   111→		// Settings are coming from the database thus secrets are encrypted
   112→		dbSettings.Settings, err = s.decryptSecrets(ctx, dbSettings.Settings)
   113→		if err != nil {
   114→			return nil, err
   115→		}
   116→	}
   117→
   118→	systemSettings, err := s.loadSettingsUsingFallbackStrategy(ctx, provider)
   119→	if err != nil {
   120→		return nil, err
   121→	}
   122→
   123→	return s.mergeSSOSettings(dbSettings, systemSettings), nil
   124→}
