   143→	storedSettings, err := s.store.List(ctx)
   144→
   145→	if err != nil {
   146→		return nil, err
   147→	}
   148→
   149→	for _, provider := range s.providersList {
   150→		dbSettings := getSettingByProvider(provider, storedSettings)
   151→		if dbSettings != nil {
   152→			// Settings are coming from the database thus secrets are encrypted
   153→			dbSettings.Settings, err = s.decryptSecrets(ctx, dbSettings.Settings)
   154→			if err != nil {
   155→				return nil, err
   156→			}
   157→		}
   158→		fallbackSettings, err := s.loadSettingsUsingFallbackStrategy(ctx, provider)
   159→		if err != nil {
   160→			return nil, err
   161→		}
   162→
   163→		result = append(result, s.mergeSSOSettings(dbSettings, fallbackSettings))
   164→	}
   165→
   166→	return result, nil
