   189→func (s *Service) Upsert(ctx context.Context, settings *models.SSOSettings, requester identity.Requester) error {
   190→	if !s.isProviderConfigurable(settings.Provider) {
   191→		return ssosettings.ErrNotConfigurable
   192→	}
   193→
   194→	reloadable, ok := s.reloadables[settings.Provider]
   195→	if !ok {
   196→		return ssosettings.ErrInvalidProvider.Errorf("provider %s not found in reloadables", settings.Provider)
   197→	}
   198→
   199→	storedSettings, err := s.GetForProvider(ctx, settings.Provider)
   200→	if err != nil {
   201→		return err
   202→	}
   203→
   204→	settingsWithSecrets, err := mergeSecrets(settings.Settings, storedSettings.Settings)
   205→	if err != nil {
   206→		return err
   207→	}
   208→	settings.Settings = settingsWithSecrets
   209→
   210→	err = reloadable.Validate(ctx, *settings, *storedSettings, requester)
   211→	if err != nil {
   212→		return err
   213→	}
   214→
   215→	settings.Settings, err = s.encryptSecrets(ctx, settings.Settings)
   216→	if err != nil {
   217→		return err
   218→	}
   219→
   220→	err = s.store.Upsert(ctx, settings)
   221→	if err != nil {
   222→		return err
   223→	}
   224→
   225→	// make a copy of current settings for reload operation and apply overrides
   226→	reloadSettings := *settings
   227→	reloadSettings.Settings = overrideMaps(storedSettings.Settings, settingsWithSecrets)
   228→
   229→	go s.reload(reloadable, settings.Provider, reloadSettings)
   230→
   231→	return nil
   232→}
