   287→func (s *Service) loadSettingsUsingFallbackStrategy(ctx context.Context, provider string) (*models.SSOSettings, error) {
   288→	loadStrategy, ok := s.getFallbackStrategyFor(provider)
   289→	if !ok {
   290→		return nil, errors.New("no fallback strategy found for provider: " + provider)
   291→	}
   292→
   293→	settingsFromSystem, err := loadStrategy.GetProviderConfig(ctx, provider)
   294→	if err != nil {
   295→		return nil, err
   296→	}
   297→
   298→	return &models.SSOSettings{
   299→		Provider: provider,
   300→		Source:   models.System,
   301→		Settings: settingsFromSystem,
   302→	}, nil
   303→}
