   416→func (s *Service) decryptSecrets(ctx context.Context, settings map[string]any) (map[string]any, error) {
   417→	configs := getConfigMaps(settings)
   418→
   419→	for _, config := range configs {
   420→		for k, v := range config {
   421→			if IsSecretField(k) && v != "" {
   422→				strValue, ok := v.(string)
   423→				if !ok {
   424→					s.logger.Error("Failed to parse secret value, it is not a string", "key", k)
   425→					return nil, fmt.Errorf("secret value is not a string")
   426→				}
   427→
   428→				decoded, err := base64.RawStdEncoding.DecodeString(strValue)
   429→				if err != nil {
   430→					s.logger.Error("Failed to decode secret string", "err", err, "value")
   431→					return nil, err
   432→				}
   433→
   434→				decrypted, err := s.secrets.Decrypt(ctx, decoded)
   435→				if err != nil {
   436→					s.logger.Error("Failed to decrypt secret", "err", err)
   437→					return nil, err
   438→				}
   439→
   440→				config[k] = string(decrypted)
   441→			}
   442→		}
   443→	}
   444→
   445→	return settings, nil
   446→}
