   287→func (s *Service) loadSettingsUsingFallbackStrategy(ctx context.Context, provider string) (*models.SSOSettings, error) {
   288→	loadStrategy, ok := s.getFallbackStrategyFor(provider)
   289→	if !ok {
   290→		return nil, errors.New("no fallback strategy found for provider: " + provider)
   291→	}
   292→
   293→	settingsFromSystem, err := loadStrategy.GetProviderConfig(ctx, provider)
   294→	if err != nil {
   295→		return nil, err
   296→	}
   297→
   298→	return &models.SSOSettings{
   299→		Provider: provider,
   300→		Source:   models.System,
   301→		Settings: settingsFromSystem,
   302→	}, nil
   303→}
   304→
   305→func getSettingByProvider(provider string, settings []*models.SSOSettings) *models.SSOSettings {
   306→	for _, item := range settings {
   307→		if item.Provider == provider {
   308→			return item
   309→		}
   310→	}
   311→	return nil
   312→}
   313→
   314→func (s *Service) getFallbackStrategyFor(provider string) (ssosettings.FallbackStrategy, bool) {
   315→	for _, strategy := range s.fbStrategies {
   316→		if strategy.IsMatch(provider) {
   317→			return strategy, true
   318→		}
   319→	}
   320→	return nil, false
   321→}
   322→
   323→func (s *Service) encryptSecrets(ctx context.Context, settings map[string]any) (map[string]any, error) {
   324→	result := deepCopyMap(settings)
   325→	configs := getConfigMaps(result)
   326→
   327→	for _, config := range configs {
   328→		for k, v := range config {
   329→			if IsSecretField(k) && v != "" {
   330→				strValue, ok := v.(string)
   331→				if !ok {
   332→					return result, fmt.Errorf("failed to encrypt %s setting because it is not a string: %v", k, v)
   333→				}
   334→
   335→				encryptedSecret, err := s.secrets.Encrypt(ctx, []byte(strValue), secrets.WithoutScope())
   336→				if err != nil {
   337→					return result, err
   338→				}
   339→				config[k] = base64.RawStdEncoding.EncodeToString(encryptedSecret)
   340→			}
   341→		}
   342→	}
   343→
   344→	return result, nil
   345→}
   346→
   347→func (s *Service) Run(ctx context.Context) error {
   348→	interval := s.cfg.SSOSettingsReloadInterval
   349→	if interval == 0 {
   350→		return nil
   351→	}
   352→
   353→	ticker := time.NewTicker(interval)
   354→
   355→	// start a background process for reloading the SSO settings for all providers at a fixed interval
   356→	// it is useful for high availability setups running multiple Grafana instances
   357→	for {
   358→		select {
   359→		case <-ticker.C:
   360→			s.doReload(ctx)
   361→
   362→		case <-ctx.Done():
   363→			return ctx.Err()
   364→		}
   365→	}
   366→}
   367→
   368→func (s *Service) doReload(ctx context.Context) {
   369→	s.logger.Debug("reloading SSO Settings for all providers")
   370→
   371→	settingsList, err := s.List(ctx)
   372→	if err != nil {
   373→		s.logger.Error("failed to fetch SSO Settings for all providers", "err", err)
   374→		return
   375→	}
   376→
   377→	for provider, connector := range s.reloadables {
   378→		settings := getSettingByProvider(provider, settingsList)
   379→
   380→		if settings == nil || len(settings.Settings) == 0 {
   381→			s.logger.Warn("SSO Settings is empty", "provider", provider)
   382→			continue
   383→		}
   384→
   385→		err = connector.Reload(ctx, *settings)
   386→		if err != nil {
   387→			s.metrics.reloadFailures.WithLabelValues(provider).Inc()
   388→			s.logger.Error("failed to reload SSO Settings", "provider", provider, "err", err)
   389→			continue
   390→		}
   391→	}
   392→}
   393→
   394→// mergeSSOSettings merges the settings from the database with the system settings
   395→// Required because it is possible that the user has configured some of the settings (current Advanced OAuth settings)
   396→// and the rest of the settings have to be loaded from the system settings
   397→func (s *Service) mergeSSOSettings(dbSettings, systemSettings *models.SSOSettings) *models.SSOSettings {
   398→	if dbSettings == nil {
   399→		s.logger.Debug("No SSO Settings found in the database, using system settings")
   400→		return systemSettings
   401→	}
   402→
   403→	s.logger.Debug("Merging SSO Settings", "dbSettings", removeSecrets(dbSettings.Settings), "systemSettings", removeSecrets(systemSettings.Settings))
   404→
   405→	result := &models.SSOSettings{
   406→		Provider: dbSettings.Provider,
   407→		Source:   dbSettings.Source,
   408→		Settings: mergeSettings(dbSettings.Settings, systemSettings.Settings),
   409→		Created:  dbSettings.Created,
   410→		Updated:  dbSettings.Updated,
   411→	}
   412→
   413→	return result
   414→}
   415→
   416→func (s *Service) decryptSecrets(ctx context.Context, settings map[string]any) (map[string]any, error) {
   417→	configs := getConfigMaps(settings)
   418→
   419→	for _, config := range configs {
   420→		for k, v := range config {
   421→			if IsSecretField(k) && v != "" {
   422→				strValue, ok := v.(string)
   423→				if !ok {
   424→					s.logger.Error("Failed to parse secret value, it is not a string", "key", k)
   425→					return nil, fmt.Errorf("secret value is not a string")
   426→				}
   427→
   428→				decoded, err := base64.RawStdEncoding.DecodeString(strValue)
   429→				if err != nil {
   430→					s.logger.Error("Failed to decode secret string", "err", err, "value")
   431→					return nil, err
   432→				}
   433→
   434→				decrypted, err := s.secrets.Decrypt(ctx, decoded)
   435→				if err != nil {
   436→					s.logger.Error("Failed to decrypt secret", "err", err)
   437→					return nil, err
   438→				}
   439→
   440→				config[k] = string(decrypted)
   441→			}
   442→		}
   443→	}
   444→
   445→	return settings, nil
   446→}
   447→
   448→func (s *Service) isProviderConfigurable(provider string) bool {
   449→	enabled, ok := s.configurableProviders[provider]
   450→	return ok && enabled
   451→}
   452→
   453→// removeSecrets removes all the secrets from the map and replaces them with a redacted password
   454→// and returns a new map
   455→func removeSecrets(settings map[string]any) map[string]any {
   456→	result := deepCopyMap(settings)
   457→	configs := getConfigMaps(result)
   458→
   459→	for _, config := range configs {
   460→		for k, v := range config {
   461→			val, ok := v.(string)
   462→			if ok && val != "" && IsSecretField(k) {
   463→				config[k] = setting.RedactedPassword
   464→			}
   465→		}
   466→	}
   467→	return result
   468→}
   469→
   470→// getConfigMaps returns a list of maps that may contain secrets
   471→func getConfigMaps(settings map[string]any) []map[string]any {
   472→	// always include the main settings map
   473→	result := []map[string]any{settings}
   474→
   475→	// for LDAP include settings for each server
   476→	if config, ok := settings["config"].(map[string]any); ok {
   477→		if servers, ok := config["servers"].([]any); ok {
   478→			for _, server := range servers {
   479→				if serverSettings, ok := server.(map[string]any); ok {
   480→					result = append(result, serverSettings)
   481→				}
   482→			}
   483→		}
   484→	}
   485→
   486→	return result
   487→}
   488→
   489→// mergeSettings merges two maps in a way that the values from the first map are preserved
   490→// and the values from the second map are added only if they don't exist in the first map
   491→// or if they contain empty URLs.
   492→func mergeSettings(storedSettings, systemSettings map[string]any) map[string]any {
   493→	settings := make(map[string]any)
   494→
   495→	for k, v := range storedSettings {
   496→		settings[k] = v
   497→	}
   498→
   499→	for k, v := range systemSettings {
   500→		if _, ok := settings[k]; !ok {
   501→			if isMergingAllowed(k) {
   502→				settings[k] = v
   503→			}
   504→		} else if isURL(k) && isEmptyString(settings[k]) {
   505→			// Overwrite all URL settings from the DB containing an empty string with their value
   506→			// from the system settings. This fixes an issue with empty auth_url, api_url and token_url
   507→			// from the DB not being replaced with their values defined in the system settings for
   508→			// the Google provider.
   509→			settings[k] = v
   510→		}
   511→	}
   512→
   513→	return settings
   514→}
   515→
   516→// isMergingAllowed returns true if the field provided can be merged from the system settings.
   517→// It won't allow SAML fields that are part of a group of settings to be merged from system settings
   518→// because the DB settings already contain one valid setting from each group.
   519→func isMergingAllowed(fieldName string) bool {
   520→	forbiddenMergePatterns := []string{"certificate", "private_key", "idp_metadata"}
   521→
   522→	for _, v := range forbiddenMergePatterns {
   523→		if strings.Contains(strings.ToLower(fieldName), strings.ToLower(v)) {
   524→			return false
   525→		}
   526→	}
   527→	return true
   528→}
   529→
   530→// mergeSecrets returns a new map with the current value for secrets that have not been updated
   531→func mergeSecrets(settings map[string]any, storedSettings map[string]any) (map[string]any, error) {
   532→	settingsWithSecrets := deepCopyMap(settings)
   533→	newConfigs := getConfigMaps(settingsWithSecrets)
   534→	storedConfigs := getConfigMaps(storedSettings)
   535→
   536→	for i, config := range newConfigs {
   537→		for k, v := range config {
   538→			if IsSecretField(k) {
   539→				strValue, ok := v.(string)
   540→				if !ok {
   541→					return nil, fmt.Errorf("secret value is not a string")
   542→				}
   543→
   544→				if !isNewSecretValue(strValue) && len(storedConfigs) > i {
   545→					config[k] = storedConfigs[i][k] // use the currently stored value
   546→				}
   547→			}
   548→		}
   549→	}
   550→
   551→	return settingsWithSecrets, nil
   552→}
   553→
   554→func overrideMaps(maps ...map[string]any) map[string]any {
   555→	result := make(map[string]any)
   556→	for _, m := range maps {
   557→		for k, v := range m {
   558→			result[k] = v
   559→		}
   560→	}
   561→	return result
   562→}
   563→
   564→// IsSecretField returns true if the SSO settings field provided is a secret
   565→func IsSecretField(fieldName string) bool {
   566→	secretFieldPatterns := []string{"secret", "private", "certificate", "password", "client_key"}
   567→
   568→	for _, v := range secretFieldPatterns {
   569→		if strings.Contains(strings.ToLower(fieldName), strings.ToLower(v)) {
   570→			return true
   571→		}
   572→	}
   573→	return false
   574→}
   575→
   576→func isURL(fieldName string) bool {
   577→	return strings.HasSuffix(fieldName, "_url")
   578→}
   579→
   580→func isEmptyString(val any) bool {
   581→	_, ok := val.(string)
   582→	return ok && val == ""
   583→}
   584→
   585→func isNewSecretValue(value string) bool {
   586→	return value != setting.RedactedPassword
   587→}
   588→
   589→func deepCopyMap(settings map[string]any) map[string]any {
   590→	newSettings := make(map[string]any)
   591→
   592→	for key, value := range settings {
   593→		switch v := value.(type) {
   594→		case map[string]any:
   595→			newSettings[key] = deepCopyMap(v)
   596→		case []any:
   597→			newSettings[key] = deepCopySlice(v)
   598→		default:
   599→			newSettings[key] = value
   600→		}
   601→	}
   602→
   603→	return newSettings
   604→}
   605→
   606→func deepCopySlice(s []any) []any {
   607→	newSlice := make([]any, len(s))
   608→
   609→	for i, value := range s {
   610→		switch v := value.(type) {
   611→		case map[string]any:
   612→			newSlice[i] = deepCopyMap(v)
   613→		case []any:
   614→			newSlice[i] = deepCopySlice(v)
   615→		default:
   616→			newSlice[i] = value
   617→		}
   618→	}
   619→
   620→	return newSlice
   621→}
