1→import config from 'app/core/config';
     2→import { contextSrv } from 'app/core/core';
     3→import { getBackendSrv } from 'app/core/services/backend_srv';
     4→import { AccessControlAction, Settings, SettingsSection } from 'app/types';
     5→
     6→import { AuthProviderInfo, GetStatusHook, AuthProviderStatus } from './types';
     7→
     8→export * from './types';
     9→
    10→const registeredAuthProviders: AuthProviderInfo[] = [];
    11→const authProvidersConfigHooks: Record<string, GetStatusHook> = {};
    12→
    13→export function registerAuthProvider(provider: AuthProviderInfo, getConfigHook?: GetStatusHook) {
    14→  if (!registeredAuthProviders.find((p) => p.id === provider.id)) {
    15→    registeredAuthProviders.push(provider);
    16→    if (getConfigHook) {
    17→      authProvidersConfigHooks[provider.id] = getConfigHook;
    18→    }
    19→  }
    20→}
    21→
    22→export function getRegisteredAuthProviders(): AuthProviderInfo[] {
    23→  return registeredAuthProviders;
    24→}
    25→
    26→export function getAuthProviderInfo(provider: string) {
    27→  return registeredAuthProviders.find((p) => p.id === provider);
    28→}
    29→
    30→export function getAuthProviders(cfg: Settings): SettingsSection[] {
    31→  const providers: SettingsSection[] = [];
    32→  for (const [section, sectionConfig] of Object.entries(cfg)) {
    33→    const provider = registeredAuthProviders.find((provider: AuthProviderInfo) => `auth.${provider.id}` === section);
    34→    if (provider) {
    35→      const providerData = {
    36→        ...sectionConfig,
    37→        providerId: provider.id,
    38→        displayName: sectionConfig.name || provider.displayName,
    39→      };
    40→      providers.push(providerData);
    41→    }
    42→  }
    43→  return providers;
    44→}
    45→
    46→export async function getAuthProviderStatus(providerId: string): Promise<AuthProviderStatus> {
    47→  if (authProvidersConfigHooks[providerId]) {
    48→    const getStatusHook = authProvidersConfigHooks[providerId];
    49→    return getStatusHook();
    50→  }
    51→  return { configured: false, enabled: false };
    52→}
    53→
    54→export function initAuthConfig() {
    55→  // skip the LDAP provider if it is enabled by SSO settings
    56→  if (config.featureToggles.ssoSettingsApi && config.featureToggles.ssoSettingsLDAP) {
    57→    return;
    58→  }
    59→
    60→  const ldapAuthProvider: AuthProviderInfo = {
    61→    id: 'ldap',
    62→    type: 'LDAP',
    63→    protocol: 'LDAP',
    64→    displayName: 'LDAP',
    65→    configPath: 'ldap',
    66→  };
    67→  registerAuthProvider(ldapAuthProvider, getConfigHookLDAP);
    68→}
    69→
    70→async function getConfigHookLDAP(): Promise<AuthProviderStatus> {
    71→  if (contextSrv.hasPermission(AccessControlAction.SettingsRead)) {
    72→    const result = await getBackendSrv().get('/api/admin/settings');
    73→    const ldapSettings = result!['auth.ldap'] || {};
    74→    return {
    75→      configured: ldapSettings['enabled'] === 'true',
    76→      enabled: ldapSettings['enabled'] === 'true',
    77→      hide: ldapSettings['enabled'] !== 'true',
    78→    };
    79→  }
    80→
    81→  return { configured: false, enabled: false };
    82→}
